    msg.payload = { response: { action: 'updateRole', ok: false, error: 'role_not_found' } };
    return [null, msg];
}
if (role.system) {
    msg.payload = { response: { action: 'updateRole', ok: false, error: 'forbidden', status: 'error', message: 'Cannot modify system roles' } };
    return [null, msg];
}
const update = { updatedAt: new Date().toISOString() };
if (d.name !== undefined) update.name = d.name;
if (d.description !== undefined) update.description = d.description;
if (d.permissions !== undefined) update.permissions = d.permissions;

msg.collection = 'dcm_roles';
msg.operation = 'updateOne';
msg.payload = [{ key: msg._updateRoleKey }, { $set: update }];
msg._updateRoleResponse = { response: { action: 'updateRole', ok: true, status: 'success' } };
return [msg, null];

const d = msg.data || {};
const roleKey = d.key || d.roleKey || '';
if (!roleKey) {
    msg.payload = { response: { action: 'deleteRole', ok: false, error: 'missing_key' } };
    return [null, msg];
}
msg._deleteRoleKey = roleKey;
msg.collection = 'dcm_roles';
msg.operation = 'findOne';
msg.payload = { key: roleKey };
return [msg, null];

const role = msg.payload;
if (!role) {
    msg.payload = { response: { action: 'deleteRole', ok: false, error: 'role_not_found' } };
    return [null, msg];
}
if (role.system) {
    msg.payload = { response: { action: 'deleteRole', ok: false, error: 'forbidden', status: 'error', message: 'Cannot delete system roles' } };
    return [null, msg];
}
msg.collection = 'dcm_roles';
msg.operation = 'deleteOne';
msg.payload = { key: msg._deleteRoleKey };
msg._deleteRoleResponse = { response: { action: 'deleteRole', ok: true, status: 'success' } };
return [msg, null];

msg.collection = 'dcm_audit_log';
msg.operation = 'find';
msg.payload = [{}];
return msg;

const docs = Array.isArray(msg.payload) ? msg.payload : [];
docs.sort((a, b) => (b.timestamp || '').localeCompare(a.timestamp || ''));
msg.payload = {
    response: {
        action: 'listAudit',
        ok: true,
        status: 'success',
        auditRows: docs.slice(0, 500)
    }
};
return msg;

var existingEmail = msg.payload;
var d = msg._createUserData;

if (d.email && existingEmail) {
    msg.payload = { response: { action: 'createUser', ok: false, error: 'validation', field: 'email', reason: 'A user with this email already exists' } };
    return [null, msg];
}

msg.collection = 'dcm_roles';
msg.operation = 'findOne';
msg.payload = { permissionsHash: d.permissionsHash, system: false };
return [msg, null];

var existingRole = msg.payload;
var d = msg._createUserData;

if (existingRole) {
    d.roleKey = existingRole.key;
    msg._createUserData = d;
    msg.payload = {};
    return [null, msg];
}

var roleKey = 'custom:' + Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
d.roleKey = roleKey;
msg._createUserData = d;

var now = new Date().toISOString();
msg.collection = 'dcm_roles';
msg.operation = 'insertOne';
msg.payload = {
    key: roleKey,
    name: 'Custom (' + d.username + ')',
    description: 'Auto-created for user',
    permissions: d.permissions,
    permissionsHash: d.permissionsHash,
    system: false,
    createdAt: now,
    updatedAt: now
};
return [msg, null];

function computeAccessLabel(accessAreas) {
    var areas = Array.isArray(accessAreas) ? accessAreas : [];
    var allFive = ['localCatalogue','catalogueRegistry','schemaRegistry','adminTools','harvest'];
    if (allFive.every(function(a) { return areas.indexOf(a) >= 0; })) return 'Full Access';
    var labelMap = { localCatalogue: 'Local Catalogue', catalogueRegistry: 'Catalogue Registry', schemaRegistry: 'Schema Registry', adminTools: 'Admin Tools', harvest: 'Harvest' };
    var order = ['localCatalogue','catalogueRegistry','schemaRegistry','adminTools','harvest'];
    var labels = [];
    for (var i = 0; i < order.length; i++) { if (areas.indexOf(order[i]) >= 0) labels.push(labelMap[order[i]]); }
    return labels.join(' + ') || 'No Access';
}

var d = msg._createUserData;
var now = new Date().toISOString();
var userDoc = msg._newUserDoc;
userDoc.accessLabel = computeAccessLabel(userDoc.accessAreas);

msg.collection = 'dcm_audit_log';
msg.operation = 'insertOne';
msg.payload = {
    timestamp: now,
    actor: msg._callerUsername,
    area: 'users',
    action: 'createUser',
    target: d.username,
    payload: { email: d.email, accessAreas: d.accessAreas },
    result: 'ok'
};
msg._createUserResponse = {
    response: {
        action: 'createUser',
        ok: true,
        status: 'success',
        user: userDoc
    }
};
return msg;

var expiredUsers = Array.isArray(msg.payload) ? msg.payload : [];
if (expiredUsers.length === 0) {
    node.status({ fill: 'green', shape: 'dot', text: 'No expired users' });
    return null;
}

var usernames = expiredUsers.map(function(u) { return u.username; });
node.status({ fill: 'yellow', shape: 'dot', text: 'Expiring ' + usernames.length + ' users' });

msg._expiredUsernames = usernames;
msg.collection = 'dcm_users';
msg.operation = 'updateMany';
msg.payload = [
    { username: { $in: usernames } },
    { $set: { status: 'expired', accessAreas: [], updatedAt: new Date().toISOString() } }
];
return msg;

var usernames = msg._expiredUsernames || [];
if (usernames.length === 0) return null;
msg.collection = 'auth_sessions';
msg.operation = 'deleteMany';
msg.payload = { username: { $in: usernames } };
return msg;

var usernames = msg._expiredUsernames || [];
node.status({ fill: 'green', shape: 'dot', text: 'Expired ' + usernames.length + ' users at ' + new Date().toISOString().slice(11,19) });
return null;

// Initialize monitoring state machine
msg._monStep = 0;
msg._monData = {};
// Step 0: count total users
msg.collection = "dcm_users";
msg.operation = "aggregate";
msg.payload = [[
  { $match: { status: { $ne: "deleted" } } },
  { $facet: {
      total: [{ $count: "n" }],
      active: [{ $match: { status: "active" } }, { $count: "n" }],
      disabled: [{ $match: { status: "disabled" } }, { $count: "n" }],
      expired: [{ $match: { expiresAt: { $lte: new Date() } } }, { $count: "n" }]
  }}
]];
return msg;

var step = msg._monStep || 0;
var data = msg._monData || {};
var result = msg.payload;
var now = new Date();

function cnt(facetArr) {
  return (Array.isArray(facetArr) && facetArr[0] && facetArr[0].n) ? facetArr[0].n : 0;
}

if (step === 0) {
  // Process user facet counts
  var facet = (Array.isArray(result) && result[0]) || {};
  data.users = {
    total: cnt(facet.total),
    active: cnt(facet.active),
    disabled: cnt(facet.disabled),
    expired: cnt(facet.expired)
  };
  // Step 1: count active sessions
  msg._monStep = 1;
  msg._monData = data;
  msg.collection = "auth_sessions";
  msg.operation = "countDocuments";
  msg.payload = { expiresAt: { $gt: now.toISOString() } };
  return [msg, null];
}

if (step === 1) {
  // Process session count
  data.sessions = { active: (typeof result === "number") ? result : 0 };
  // Step 2: audit activity last 24h — use facet
  var oneDayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);
  msg._monStep = 2;
  msg._monData = data;
  msg.collection = "dcm_audit_log";
  msg.operation = "aggregate";
  msg.payload = [[
    { $match: { timestamp: { $gte: oneDayAgo.toISOString() } } },
    { $facet: {
        loginSuccess: [{ $match: { action: "login.success" } }, { $count: "n" }],
        loginFailed: [{ $match: { action: "login.failed" } }, { $count: "n" }],
        loginBlocked: [{ $match: { action: "login.blocked.disabled" } }, { $count: "n" }],
        userUpdated: [{ $match: { action: "updateUser" } }, { $count: "n" }],
        userDeleted: [{ $match: { action: "deleteUser" } }, { $count: "n" }]
    }}
  ]];
  return [msg, null];
}

if (step === 2) {
  // Process activity facet
  var facet = (Array.isArray(result) && result[0]) || {};
  data.activity24h = {
    logins: cnt(facet.loginSuccess),
    loginsFailed: cnt(facet.loginFailed),
    loginsBlockedDisabled: cnt(facet.loginBlocked),
    userUpdates: cnt(facet.userUpdated),
    userDeletions: cnt(facet.userDeleted)
  };
  // Step 3: count audit events last 7 days
  var sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
  msg._monStep = 3;
  msg._monData = data;
  msg.collection = "dcm_audit_log";
  msg.operation = "countDocuments";
  msg.payload = { timestamp: { $gte: sevenDaysAgo.toISOString() } };
  return [msg, null];
}

if (step === 3) {
  data.audit7dCount = (typeof result === "number") ? result : 0;
  // Step 4: recent audit log (last 20)
  msg._monStep = 4;
  msg._monData = data;
  msg.collection = "dcm_audit_log";
  msg.operation = "find";
  msg.payload = [{}];
  return [msg, null];
}

if (step === 4) {
  var docs = Array.isArray(result) ? result : [];
  docs.sort(function(a, b) { return (b.timestamp || "").localeCompare(a.timestamp || ""); });
  data.recentAudit = docs.slice(0, 20).map(function(r) {
    return {
      at: r.timestamp || r.at || null,
      action: r.action || "",
      actor: r.actor || r.actorUsername || r.actorId || "system",
      target: r.target || r.targetUsername || r.targetUserId || null,
      meta: r.payload ? JSON.stringify(r.payload).substring(0, 200) : (r.message || null)
    };
  });
  // Step 5: heartbeats
  msg._monStep = 5;
  msg._monData = data;
  msg.collection = "dcm_heartbeats";
  msg.operation = "find";
  msg.payload = [{}];
  return [msg, null];
}

if (step === 5) {
  var heartbeats = Array.isArray(result) ? result : [];
  var moduleNames = ["SchemaRegistry","CatalogueRegistry","Harvester","AdminTools","Auth","LocalCatalogue"];
  data.modules = moduleNames.map(function(name) {
    var hb = null;
    for (var i = 0; i < heartbeats.length; i++) {
      if (heartbeats[i].module === name) { hb = heartbeats[i]; break; }
    }
    if (!hb) return { module: name, status: "unknown", lastSeen: null };
    var ageSec = (now - new Date(hb.at)) / 1000;
    var status = ageSec < 90 ? "up" : ageSec < 300 ? "degraded" : "down";
    return { module: name, status: status, lastSeen: hb.at };
  });
  data.generatedAt = now.toISOString();

  msg.payload = {
    response: {
      action: "getMonitoringOverview",
      ok: true,
      status: "success",
      data: data
    }
  };
  return [null, msg];
}

// Fallback
msg.payload = { response: { action: "getMonitoringOverview", ok: false, error: "internal_error" } };
return [null, msg];

msg.collection = "dcm_heartbeats";
msg.operation = "updateOne";
msg.payload = [
  { module: "AdminTools" },
  { $set: { module: "AdminTools", at: new Date().toISOString() } },
  { upsert: true }
];
return msg;
